insert into products (supplier,supplier_sku,name,slug,category,subcategory,description,seo_description,min_qty,is_published,decoration_model,decoration_source,size_chart,colours,indent_type,brand) values
  ('Trends','133818','Bodum Pavina Double Wall Glasses - Large - Set of 2','bodum-pavina-double-wall-glasses-large-set-of-2-133818','Drinkware','Glassware','Innovative 450ml double wall glass tumblers designed for versatility. Made from mouth-blown, heat-resistant borosilicate glass, the double wall maintains beverage temperature while ensuring the glass remains comfortable to hold. A silicone vent at the base equalises air pressure between the glass layers, reducing condensation and heat transfer. Suitable for hot or cold drinks, soups and desserts, it offers a wide range of serving options in a single glass design. Microwave and oven safe. Presented in a printed Bodum branded gift box.','Brand the the Bodum Pavina Double Wall Glasses - Large - Set of 2 with imitation etch per position (both glasses) or pad print per colour/position (both glasses) — innovative 450ml double wall glass tumblers designed for versatility. From 6 units.',6,true,null,'supplier',null,'[{"name": "Clear", "hex": "#EAF3F7", "image": ""}]'::jsonb,null,null);
